const hexToVec = (hex) => {
  const n = parseInt(hex.slice(1), 16);
  return new THREE.Vector3(((n >> 16) & 255) / 255, ((n >> 8) & 255) / 255, (n & 255) / 255);
};
const hslToHex = (h, s, l) => {
  s /= 100; l /= 100;
  const k = (n) => (n + h / 30) % 12;
  const a = s * Math.min(l, 1 - l);
  const f = (n) => { const c = l - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1))); return Math.round(255 * c).toString(16).padStart(2, "0"); };
  return `#${f(0)}${f(8)}${f(4)}`;
};
const rampFromColor = (c) => {
  const h = c.h, s = c.s;
  return [hslToHex(h, Math.min(s, 40), 6), hslToHex(h, s, 18), hslToHex(h, s, 42), hslToHex(h, s, 62), hslToHex(h, Math.max(s - 20, 20), 88)];
};

