const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Bodoni+Moda:ital,wght@0,400;0,500;1,400&family=Archivo:wght@400;600&display=swap');
* { box-sizing: border-box; }
html, body, #root { margin: 0; padding: 0; width: 100%; min-height: 100%; }
html { scroll-behavior: smooth; }
section[id] { scroll-margin-top: 84px; }
.aud-card:hover { transform: translateY(-4px); border-color: #c9a25e88; }
body { background: #0c0a08; }
@keyframes shimmer { to { background-position: 200% center; } }
.liquidText { background-image: linear-gradient(100deg,#8a6a3a,#e9d4a3,#fff4dd,#c9a25e,#8a6a3a); background-size: 250% auto; -webkit-background-clip: text; background-clip: text; -webkit-text-fill-color: transparent; color: transparent; animation: riseIn 1.1s cubic-bezier(.2,.8,.2,1) both, shimmer 5s linear infinite; }
@keyframes riseIn { 0% { opacity: 0; transform: translateY(28px); filter: blur(6px); } 100% { opacity: 1; transform: translateY(0); filter: blur(0); } }
.rise { animation: riseIn 1.1s cubic-bezier(.2,.8,.2,1) both; }
.marquee { animation: scroll 26s linear infinite; }
@keyframes scroll { to { transform: translateX(-50%); } }
.navlink { transition: color .3s, letter-spacing .3s; }
.navlink:hover { color: #c9a25e !important; letter-spacing: 3px; }
.card:hover { background: #14110c88 !important; transform: translateY(-6px); }
.card:hover .sheen { left: 120%; }
.cell:hover { transform: scale(1.5); border-radius: 4px; box-shadow: 0 6px 18px #000000aa; position: relative; z-index: 3; }
.chip:hover { border-color: #c9a25e !important; color: #fff !important; }
.zoom-btn:hover { border-color: #c9a25e !important; color: #fff !important; }
.search-input:focus { border-color: #c9a25e !important; box-shadow: 0 0 0 3px #c9a25e22; }
.search-input::placeholder { color: #8f877a; }
.theme-btn:hover { border-color: #c9a25e !important; transform: translateY(-2px); }
.dc-tab:hover { border-color: #c9a25e !important; transform: translateY(-3px); }
.dc-sw:hover .dc-sw-color, .dc-sw:hover span:first-child { transform: scale(1.05); box-shadow: 0 8px 22px #000000aa; }
.dc-fade { animation: fadeUp .5s ease both; }
@keyframes fadeUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
.cta-prim { transition: transform .3s, box-shadow .3s; }
.cta-prim:hover { transform: translateY(-2px); box-shadow: 0 12px 30px #c9a25e55; }
.cta-ghost { transition: background .3s, color .3s, border-color .3s; }
.cta-ghost:hover { background: #ece6db; color: #0c0a08 !important; border-color: #ece6db; }
.flip-spin { animation: spin 0.8s linear infinite; }
@keyframes spin { to { transform: rotate(360deg); } }
.flipbook { margin: 0 auto; }
.porta:hover { transform: translateY(-6px); border-color: #ffffff44 !important; }
.nav-burger:hover { border-color: #c9a25e !important; }
@media (min-width: 781px) { .mobile-menu { display: none !important; } }
@media (max-width: 780px) {
  .nav-links { display: none !important; }
  .nav-orcamento { display: none !important; }
  .nav-burger { display: flex !important; }
  nav { padding: 16px 4vw !important; }
  section:not(.hero) { padding-top: 76px !important; padding-bottom: 76px !important; }
  #contato { padding-top: 96px !important; padding-bottom: 64px !important; }
  .marquee { font-size: 19px !important; }
  /* layouts 2-col -> empilha (mantém o grid de paletas do painel, gap:10, intacto) */
  [style*="grid-template-columns: 2fr 1fr"] { grid-template-columns: 1fr !important; }
  [style*="grid-template-columns: 1fr 1fr"][style*="gap: 22"] { grid-template-columns: 1fr !important; }
  [style*="grid-template-columns: 1fr 1fr"][style*="gap: 56"] { grid-template-columns: 1fr !important; }
  #pintores { grid-template-columns: 1fr !important; }
}
@media (max-width: 480px) {
  .fx-panel { width: calc(100vw - 28px) !important; right: 14px !important; bottom: 84px !important; }
}
`;
